const Q_CHEMISTRY_2012=[{"id": "objective>Chemistry>2012>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which subject paper is this?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Chemistry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Physics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Biology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Agric</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The subject paper is Chemistry as indicated by the id of the question.</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2012>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following methods can be used to obtain pure water from a mixture of sand, water and methanoic acid?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Neutralization with NaOH followed by filtration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Neutralization with NaOH followed by distillation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fraction distillation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Filtration followed by distillation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mixture contains sand, water and methanoic acid. The first step would be to neutralize the acid with NaOH forming salt, water and sand. The next step to obtain pure water is by subjecting the resulting solution to distillation as distillation is used to recover a solvent from its solution. </div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2012>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many atoms are present in 6.0g of magnesium?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.20 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">22</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.41 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">22</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.51 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.02 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The number of atoms in a given amount of substance can be calculated using Avogadro's number (6.022 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span> atoms/mole). The molar mass of magnesium is 24.305 g/mole. Therefore, 6.0g of magnesium contains (6.0g /mole) * (6.022 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span> atoms/mole) = 1.51 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span> atoms.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2012>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a gas was collected over water at 10°C and 765 mm Hg. Calculate the volume of the gas at s.t.p. if the saturated vapour pressure of water at 10°C is 5mm Hg.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">49.19cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">48.87cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">48.55cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">48.23cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 765 - 5 = 760 mmHg; V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>; T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 10 + 273 = 283K;  <br/>   P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 760 mmhg; V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = ?; T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 273;  <br/>   P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>  <br/>  V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = (760 × 50 × 273)/(283 × 760) = 48.23cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : COMBINED GAS LAW,MOLAR VOLUME AND ATOMICITY OF GASES"}, {"id": "objective>Chemistry>2012>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in the pressure exerted on a gas at a constant temperature results in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the number of effective collisions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in volume</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the average intermolecular distance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in volume</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Boyle's Law, the volume of a given mass of gas is inversely proportional to its pressure, provided the temperature remains constant. Therefore, an increase in pressure results in a decrease in volume.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2012>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>  <br/>  In the reaction above, what volume of hydrogen would be left over when 300cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of oxygen and 1000 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of hydrogen are exploded in a sealed tube?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">200cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">400cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">600cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">700cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>  → 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> ,  <br/>  Mole of reactants ratio =2:1,   <br/>  Note that : 300cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> will require 600cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> according to the ratio  <br/>  Hence, unreacted H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>  = 1000cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>- 600cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 400cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "CHEMICAL COMBINATION : GAY LUSSAC'S LAW OF COMBINING VOLUMES"}, {"id": "objective>Chemistry>2012>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Evaporation   <br/>  II. Sublimation   <br/>  III. Diffusion   <br/>  IV. Brownian motion  <br/>  Which of the above can correctly be listed  as evidences for the particulate nature of matter?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and III only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, III and IV</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The particulate nature of matter is evidenced in evaporation, Sublimation diffusion and brownian motion.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2012>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the elements X and Y have atomic numbers 11 and 17 respectively, what type of bond can they form?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Dative </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Covalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ionic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Metallic</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">X and Y will form ionic bond as X donates its outermost single electron to Y so that they can both attain a stable octet electronic configuration.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2012>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A deuterium atom which has lost an electron contains</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">one proton only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one neutron only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one proton and one neutron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one proton, one electron and one neutron</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A deuterium atom contains one proton, one neutron and one electron. Losing an electron leaves it with only a proton and a neutron. Note that deuterium is an isotope of hydrogen with an atomic mass of 2.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2012>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The electronic configuration of Mg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Note that Mg has 12 electrons, it loses two electrons to become Mg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>. Therefore, Mg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> = 10electrons = 2,8  = 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>, 2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> 2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> </div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2012>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Group VII elements are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">monoatomic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">good oxidizing agents</div>", "<div style=\"font-family:Cambria;font-size:17px;\">highly electropositive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electron donors</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Group VII elements are good oxidizing agents. They are also known as halogens and they have seven electrons in their outermost shell. They need one more electron to achieve a stable electron configuration, and thus, they have a strong tendency to gain an electron, making them good oxidizing agents.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2012>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is used to study the arrangement of particles in crystal lattices?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Alpha-particles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Beta-particles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gamma-rays </div>", "<div style=\"font-family:Cambria;font-size:17px;\">X-rays</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">X-rays are used to study the arrangement of particles in crystal lattices. This is done through a technique known as X-ray crystallography, which involves directing X-rays at a crystal and measuring the angles and intensities of the diffracted rays to determine the electron density within the crystal and hence the positions of the atoms.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : SHAPES OF SIMPLE MOLECULES"}, {"id": "objective>Chemistry>2012>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. It has a varied composition from one place to another  <br/>  II. Its constituents can be separated by physical means  <br/>  III. It contains unreactive noble gases  <br/> Which of the above shows that air is a mixture?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and II only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only. I. It has a varied composition from one place to another  <br/>  II. Its constituents can be separated by physical means  <br/>  III. It contains unreactive noble gases </div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2012>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The chemicals used to soften hard water involves the addition of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">insoluble sodium compounds which form soluble solutions of calcium and magnesium ions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">soluble sodium compounds which form soluble solutions of calcium and magnesium ions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">soluble sodium compounds which form insoluble precipitates of calcium and magnesium ions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">insoluble sodium compounds which form insoluble precipitates of calcium and magnesium ions.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The chemicals used to soften hard water involves the addition of soluble sodium compounds which form insoluble precipitates of calcium and magnesium ions.</div>", "topic": "WATER : PURIFICATION OF TOWN WATER SUPPLIES"}, {"id": "objective>Chemistry>2012>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Chlorination of water for town supply is carried out to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">make the water colourless</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remove germs from the water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make the water tasteful</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remove odour from the water</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chlorination of water for town supply is carried out to remove germs from the water. Chlorine is a disinfectant that kills bacteria and other microorganisms in the water, making it safe to drink.</div>", "topic": "WATER : PURIFICATION OF TOWN WATER SUPPLIES"}, {"id": "objective>Chemistry>2012>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The solubilities of different solutes in a given solvent can be compared by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">plotting their solubility curves on separate axes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plotting their solubility curves on the same axes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plotting some of the solubility curves on the x-axis and others on the y-axis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plotting their solubility curves on the x-axis only.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The solubilities of different solutes in a given solvent can be compared by plotting their solubility curves on the same axis.</div>", "topic": "SOLUBILITY : SOLVENTS"}, {"id": "objective>Chemistry>2012>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Potassium trioxochlorate(V) has a solubility of 1.5mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> at 45°C. On cooling this solution to a temperature of 20°C, the solubility was found to be 0.5 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>. What mass of KClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> was crystallized out?  <br/> [Molar Mass of KClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>= 122.5gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.00g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.00g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.25g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">122.50g</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> At 45°C, solubility = 1.5 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>  <br/>  At 20°C, solubility = 0.5 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>  <br/>  Cooling from 45°C to 20°C gives 1.5mol - 0.5mol = 1mol  <br/>  <br/>  Mass of 1 mole KClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>= 122.5g <br/> Mass of KClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> crystalized out  = no of mole  x molar mass  <br/>  = 1 x 122.50 <br/>  = 122.50</div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>2012>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following pollutants is associated with brain damage?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Carbon (II) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Radioactive fallout</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Biodegradable waste</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur (IV) oxide</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon (II) oxide is associated with brain damage. </div>", "topic": "ENVIRONMENTAL POLLUTION : SOURCES AND EFFECTS OF POLLUTANTS"}, {"id": "objective>Chemistry>2012>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following will produce a solution with pH less than 7 at equivalent point?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> + NaOH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + KOH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCl + Mg(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> + KOH</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">HCl + Mg(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> will produce a solution with pH less  than 7  (acidic) because it is a reaction between a strong acid and a weak base.</div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>2012>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The number of hydroxonium ions produced by one molecule of an acid in aqueous solution is its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">basicity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">acid strength</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pH </div>", "<div style=\"font-family:Cambria;font-size:17px;\">concentration</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Basicity is the number of replacable (or ionizable) hydroxonium ions or hydrogen ions present in one molecule of an acid in aqueous solution.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2012>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During a titration experiment, 0.05 mole of carbon(IV)oxide is liberated. What is the volume of gas liberated?  <br/>  [Molar Volume of gas at s.t.p. = 22.4 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">22.40 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">11.20 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.24 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.12 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">1 mole of gas = 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>  <br/> 0.05 mole of gas = 0.05 x 22.4 = 1.12dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "CHEMICAL COMBINATION : AVOGADRO'S LAW"}, {"id": "objective>Chemistry>2012>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major factor considered in selecting a suitable method for preparing a simple salt is its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">crystalline form</div>", "<div style=\"font-family:Cambria;font-size:17px;\">melting point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reactivity with dilute acids</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solubility in water</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Solubility in water is a major factor considered in preparing a simple salt.</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2012>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation number of boron in NaBH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">-3 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">-1 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">+1 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">+3</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sum of oxidation number of a NaBH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> = 0 <br/> Oxidation number of Na = +1 <br/> Oxidation number of B = ? <br/> Oxidation number of H = -1; because this is a metal hydride <br/> Therefore:(+1) + B + 4(-1)=0 <br/> (+1) + B - 4=0 <br/> B = 4-1 = +3  </div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2012>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(s)</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> → 4NaOH(s) + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>  <br/>  The substance that is oxidized in the reaction above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(s)</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaOH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O is oxidized to O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> because hydrogen is removed from it. Note that oxidation could mean the removal of hydrogen.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2012>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What number of moles of Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> will be deposited by 360 coulombs of electricity? <br/>  [F = 96500C mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.36 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> mole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.87 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> mole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.35 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> mole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.73 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> mole</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Cu  <br/>  2 x 96500C  →  1 mole of Cu   <br/> 360C  →  x  =  360/(2 x 96500) = 1.87 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>mole</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2012>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A metal M displaces zinc from ZnCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> solution. This shows that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">electrons flow from zinc to M.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">M is more electropositive than zinc </div>", "<div style=\"font-family:Cambria;font-size:17px;\">M is more electronegative than zinc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zinc is more electropositive than M</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">M is more electropositive than zinc as only a more electropositive metal can displace another from a solution of its salt.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALLOY"}, {"id": "objective>Chemistry>2012>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> <br/> Calculate the standard heat change of the reaction above, if the standard enthalpies of formation of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>, H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> and CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> in kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> are -394, -242 and -110 respectively.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">+262 kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">-262 kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">+42 kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">-42 kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Standard heat change for the reaction, ΔH = H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(pr,CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)</span>-H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">rxt(CO, H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O)</span> = -394- (-242-110) = -394 + 352 = - 42KJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2012>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in entropy can best be illustrated by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mixing of gases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">freezing of water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the condensation of vapour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solidifying candle wax</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Entropy is a measure of the disorder or randomness of a system. The mixing of gases results in an increase in entropy because the gases become more disordered as they mix. The other options involve changes of state from a more disordered state to a less disordered state, which would decrease entropy.</div>", "topic": "ENERGY CHANGES : ENTROPY"}, {"id": "objective>Chemistry>2012>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The highest rate of production of carbon(IV)oxide can be achieved using</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.05 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> HCl and 5g powdered CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.05 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> HCl and 5g lump CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.10 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> HCl and 5g powdered CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.025 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> HCl and 5g powdered CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The highest rate of production of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is achieved using 0.1 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> HCl and 5g powdered CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, due to high concentration and surface area.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2012>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  2HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq) </span>+ CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(s)</span> → CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(s)</span> + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span>   <br/>  From the reaction above, which of the curves represents the production of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> gas as dilute HCl is added?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">L </div>", "<div style=\"font-family:Cambria;font-size:17px;\">M </div>", "<div style=\"font-family:Cambria;font-size:17px;\">N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">P</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The curve 'N' represents the production of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> as dilute HCl is added.</div>", "topic": "RATE OF CHEMICAL REACTION : CONCENTRATION OR TIME CURVES"}, {"id": "objective>Chemistry>2012>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> ⇔ 2CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> <br/> In the reaction above, high pressure will favour the forward reaction because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">high pressure favours gas formation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the reaction is in dynamic equilibrium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the reaction is exothermic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the process occurs with a decrease in volume</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">High pressure favours the forward reaction because it occurs with decrease in volume,that is a decrease in the number of moles of gaseous species.</div>", "topic": "CHEMICAL EQUILIBRIA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2012>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A piece of filter paper moistened with lead(II)ethanoate solution turns black when the paper is dropped into a gas jar containing an unknown gas. The gas is likely to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sulphur(IV)oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sulphur(VI)oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen sulphide</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen sulphide can acts as precipitating agent by reacting with lead (II) ethanoate solution. In this reaction, lead sulphide (Black-coloured) is formed along with ethanoic acid.  <br/> Pb(CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COO)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S → PbS <span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(Black)</span>+ 2CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH  <br/>  Note that this has been explained in a previous question.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HYDROGEN"}, {"id": "objective>Chemistry>2012>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following gases has a characteristic pungent smell, turns red litmus paper blue and forms dense white fumes with hydrogen chloride gas?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ammonia possess the characteristics listed. NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> is basic: It turns red litmus blue, it has a pungent smell, it forms a dense white frame on reaction with hydrogen chloride. </div>", "topic": "NON-METALS AND THEIR COMPOUNDS : NITROGEN"}, {"id": "objective>Chemistry>2012>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Commercial bleaching can be carried out using</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sulphur(IV))oxide and ammonia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen sulphide and chlorine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorine and sulphur (IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ammonia and chlorine</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Commercial bleaching is often carried out using chlorine and sulphur (IV) oxide. Chlorine is a strong oxidizing agent that can bleach by breaking the chemical bonds in the chromophore (part of a molecule responsible for its color). Sulphur (IV) oxide acts as a reducing agent.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HALOGENS"}, {"id": "objective>Chemistry>2012>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Mineral acids are usually added to commercial hydrogen peroxide to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oxidize it</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decompose it</div>", "<div style=\"font-family:Cambria;font-size:17px;\">minimize its decomposition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce it to water and oxygen</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mineral acids are usually added to commercial hydrogen peroxide to minimize its decomposition. Hydrogen peroxide (H2O2) is unstable and decomposes easily to water and oxygen. The addition of mineral acids helps to stabilize it and prevent this decomposition.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2012>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following compounds will burn with a brick-red colour in a nonluminous Bunsen flame?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">LiCl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaCl </div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">MgCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Calcium chloride (CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) burns with a brick-red flame in a nonluminous Bunsen flame. This is due to the energy levels of the electrons in calcium atoms, which absorb energy from the flame and then emit it as light in the red part of the spectrum when they return to their original energy levels.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2012>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The purest form of iron which contains only about 0.1% carbon is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pig iron </div>", "<div style=\"font-family:Cambria;font-size:17px;\">wrought iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cast iron </div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron pyrite</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wrought iron is the purest form of iron which contains only about 0.1% carbon. It is a very pure form of iron, which is used for decorative work, gates, and railings. It is tough, malleable, ductile and can be easily welded.</div>", "topic": "METALS AND THEIR COMPOUNDS : IRON"}, {"id": "objective>Chemistry>2012>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A common characteristic between zinc and the other transition elements is the ability to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">have variable oxidation states</div>", "<div style=\"font-family:Cambria;font-size:17px;\">form complex ions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">act as a catalyst</div>", "<div style=\"font-family:Cambria;font-size:17px;\">form coloured ions</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Zinc does not posses many of the properties that characterize the transition metals as: <br/>  <br/>  1. It has only one oxidation state  <br/>  <br/>  2. Its metallic ions are not coloured  <br/>  <br/>  3. It is not used as catalyst  <br/> However, zinc form complexes like the other transition metals </div>", "topic": "METALS AND THEIR COMPOUNDS : METALS OF THE FIRST TRANSITION SERIES"}, {"id": "objective>Chemistry>2012>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following metals is the least reactive?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pb </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sn </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hg </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Au</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gold (Au) is the least reactive metal among the given options. Reactivity of metals is determined by how readily a metal can lose its electrons to form positive ions. Gold is a noble metal and it is very low in the reactivity series, meaning it doesn't react easily with other substances.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALLOY"}, {"id": "objective>Chemistry>2012>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Geometric isomerism can exist in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hex-3-ene </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hexane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prop-1-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3-methylbut-1-ene</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Geometric isomerism can exist in hex-3-ene. Geometric isomerism is a form of stereoisomerism and describes the orientation of functional groups at the ends of a molecule with a carbon-carbon double bond. Hex-3-ene has a carbon-carbon double bond and can therefore exhibit geometric isomerism.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2012>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Alkanals can be distinguished from alkanones by the reaction with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sudan III stain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">starch iodide paper</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lithium tetrahydrido aluminate (III)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fehling's solution</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Alkanals can be distinguished from alkanones by the reaction with fehling's solution. The alkanals give a brick red precipitate being reducing agent while the alkanones do not.</div>", "topic": "ORGANIC COMPOUNDS : ALKANALS AND ALKANONES"}, {"id": "objective>Chemistry>2012>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The isomers of C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>O are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1-propanol and 2-propanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1-propanol and 1-propanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-propanol and 2-propanone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-propanol and 1-propanal</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Propan-1-ol and propane-2-ol have the same molecular formular, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>OH = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>O and different structural formulas. This agrees with isomerism. </div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2012>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Carbohdrates are large molecules with the molecular formula C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span>(H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span>. In which of the following pairs is x not equal to y?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Glucose and starch</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Maltose and fructose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sucrose and fructose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Maltose and starch</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Starch = (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>)n. maltose = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">22</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">11</span>.</div>", "topic": "ORGANIC COMPOUNDS : CARBOHYDRATES"}, {"id": "objective>Chemistry>2012>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A compound contains 40.0% C, 6.7% H and 53.3% O. If the molecular mass of the compound is 180, its molecular formula is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O </div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Percentage composition</td><td style=\"border:1px solid black;text-align:center;\"> C</td><td style=\"border:1px solid black;text-align:center;\"> H</td><td style=\"border:1px solid black;text-align:center;\"> O  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 400</td><td style=\"border:1px solid black;text-align:center;\"> 6.7</td><td style=\"border:1px solid black;text-align:center;\"> 53.3  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Molar composition</td><td style=\"border:1px solid black;text-align:center;\"> 40/12</td><td style=\"border:1px solid black;text-align:center;\"> 6.7/1</td><td style=\"border:1px solid black;text-align:center;\"> 53.3/16 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 3.33</td><td style=\"border:1px solid black;text-align:center;\"> 6.7</td><td style=\"border:1px solid black;text-align:center;\"> 3.33  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Mole ratio</td><td style=\"border:1px solid black;text-align:center;\"> 1</td><td style=\"border:1px solid black;text-align:center;\"> 2</td><td style=\"border:1px solid black;text-align:center;\"> 1</td></tr></table></div> <br/> Emperical formular  = CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> (Emperical formular)n  = molecular mass (CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O)n = 180 <br/> (12 + 2 + 16)n = 180 <br/> 30n = 180, n = 6 <br/> (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span> = (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>)</div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2012>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The alkyne that will give a white precipitate with silver trioxonitrate(V) is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>C ≡ CCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>C ≡ CCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>C ≡ CH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>C ≡ CCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Silver trioxonitrate(V) reacts with terminal alkynes to give a white precipitate of silver acetylide. The alkyne that will give a white precipitate with silver trioxonitrate(V) is CH3CH2CH2CH2C ≡ CH, because it is a terminal alkyne, meaning the triple bond is at the end of the molecule.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2012>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The saponification of an alkanoate to produce soap and alkanol involves</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dehydration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">esterification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrolysis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxidation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Saponification is the process of making soap. It involves the hydrolysis of an alkanoate (or ester) in the presence of a base. The products of this reaction are soap (a salt of a fatty acid) and an alkanol.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOATES"}, {"id": "objective>Chemistry>2012>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2-methylpropan-2-ol is an example of a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">primary alkanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">secondary alkanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tertiary alknaol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quartenary alkanol</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2-methylpropan-2-ol is an example of a tertiary alkanol. Tertiary alkanols are those in which the carbon atom that carries the OH group is directly linked to three other carbon atoms. In 2-methylpropan-2-ol, the carbon atom carrying the OH group is linked to three other carbon atoms.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2012>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The final oxidation product of alkanol,alkanal and alkanones is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alkanoic acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanoyl halide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanoate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanamide</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The final oxidation product of alkanol, alkanal, and alkanones is alkanoic acid. This is because alkanol, alkanal, and alkanones are all organic compounds that contain a carbon chain. When these compounds undergo oxidation, the carbon chain is broken down and replaced with oxygen atoms, forming a carboxylic acid group (-COOH), which is characteristic of alkanoic acids.</div>", "topic": "ORGANIC COMPOUNDS : ALKANALS AND ALKANONES"}, {"id": "objective>Chemistry>2012>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ethanol reacts with concentrated tetraoxosulphate(VI)acid at a temperature above 170°C to form</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethanone </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethyne </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanal</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ethanol reacts with conc. H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> at a temperature above 170°C  to form ethene.  <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>  →<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">180<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</span> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>HSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O  <br/>  <img src=\"2012/k42.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2012>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of oxidation-reduction enzyme is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">amylase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">protease</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lipase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dehydrogenase</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dehydrogenase is an example of an oxidation-reduction enzyme. Oxidation-reduction (redox) reactions involve the transfer of electrons from one molecule to another. Dehydrogenase enzymes facilitate these reactions by removing hydrogen atoms (which include an electron) from a substrate molecule (oxidation) and transferring them to another molecule (reduction).</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}];
